using UnityEngine;
using UnityEngine.UI;
using System.Collections.Generic;
using TowerDefense.Data;

namespace TowerDefense.UI
{
    public class ShopPanel : MonoBehaviour
    {
        [Header("Panel")]
        [SerializeField] private GameObject _shopPanel;
        [SerializeField] private Button _closeButton;

        [Header("Tabs")]
        [SerializeField] private Button _tabResource;
        [SerializeField] private Button _tabHero;
        [SerializeField] private Button _tabTower;
        [SerializeField] private Button _tabSpecial;
        [SerializeField] private Color _tabActiveColor = new Color(1f, 0.85f, 0.3f, 1f);
        [SerializeField] private Color _tabInactiveColor = new Color(0.6f, 0.6f, 0.6f, 1f);

        [Header("Content")]
        [SerializeField] private Transform _itemContainer;
        [SerializeField] private GameObject _shopItemPrefab;

        [Header("Data")]
        [SerializeField] private string _jsonPath = "Data/ShopItems";

        private ShopData _shopData;
        private ShopCategory _currentCategory;
        private List<GameObject> _spawnedItems = new List<GameObject>();
        private Dictionary<ShopCategory, Button> _tabButtons = new Dictionary<ShopCategory, Button>();

        private void Awake()
        {
            _tabButtons[ShopCategory.Resource] = _tabResource;
            _tabButtons[ShopCategory.Hero] = _tabHero;
            _tabButtons[ShopCategory.Tower] = _tabTower;
            _tabButtons[ShopCategory.Special] = _tabSpecial;

            if (_closeButton != null)
                _closeButton.onClick.AddListener(CloseShop);

            foreach (var kvp in _tabButtons)
            {
                if (kvp.Value != null)
                {
                    var cat = kvp.Key;
                    kvp.Value.onClick.AddListener(() => SwitchTab(cat));
                }
            }

            LoadShopData();
        }

        private void Start()
        {
            if (_shopPanel != null)
                _shopPanel.SetActive(false);
        }

        private void LoadShopData()
        {
            var jsonFile = Resources.Load<TextAsset>(_jsonPath);
            if (jsonFile != null)
            {
                _shopData = JsonUtility.FromJson<ShopData>(jsonFile.text);
                Debug.Log($"[ShopPanel] Loaded {_shopData.items.Length} items from JSON");
            }
            else
            {
                Debug.LogError($"[ShopPanel] Failed to load JSON: Resources/{_jsonPath}");
                _shopData = new ShopData { items = new ShopItemData[0] };
            }
        }

        public void OpenShop()
        {
            if (_shopPanel != null)
                _shopPanel.SetActive(true);

            LoadShopData();
            SwitchTab(ShopCategory.Resource);
        }

        public void CloseShop()
        {
            if (_shopPanel != null)
                _shopPanel.SetActive(false);
        }

        private void SwitchTab(ShopCategory category)
        {
            _currentCategory = category;
            UpdateTabVisuals();
            RefreshItemList();
        }

        private void UpdateTabVisuals()
        {
            foreach (var kvp in _tabButtons)
            {
                if (kvp.Value == null) continue;
                var colors = kvp.Value.colors;
                colors.normalColor = kvp.Key == _currentCategory ? _tabActiveColor : _tabInactiveColor;
                colors.selectedColor = colors.normalColor;
                colors.highlightedColor = kvp.Key == _currentCategory ? _tabActiveColor : new Color(0.8f, 0.8f, 0.8f, 1f);
                kvp.Value.colors = colors;
            }
        }

        private void RefreshItemList()
        {
            foreach (var item in _spawnedItems)
            {
                if (item != null) Destroy(item);
            }
            _spawnedItems.Clear();

            if (_itemContainer == null || _shopItemPrefab == null)
            {
                Debug.LogWarning("[ShopPanel] Item container or prefab is null");
                return;
            }

            foreach (var itemData in _shopData.items)
            {
                if (itemData.category != _currentCategory) continue;

                GameObject itemObj = Instantiate(_shopItemPrefab, _itemContainer);
                _spawnedItems.Add(itemObj);

                var shopItemUI = itemObj.GetComponent<ShopItemUI>();
                if (shopItemUI != null)
                {
                    shopItemUI.Setup(itemData, this);
                }
            }
        }

        public void OnBuyClicked(ShopItemData itemData)
        {
            if (itemData.isLimited && itemData.purchasedCount >= itemData.limitCount)
            {
                Debug.Log($"[ShopPanel] {itemData.name} 已达购买上限");
                return;
            }

            string currencyName = itemData.currencyType switch
            {
                CurrencyType.Gold => "金币",
                CurrencyType.Diamond => "钻石",
                CurrencyType.Free => "免费",
                _ => "未知"
            };

            Debug.Log($"[ShopPanel] 购买: {itemData.name}, 价格: {(itemData.discount > 0 ? itemData.price * (100 - itemData.discount) / 100 : itemData.price)} {currencyName}");

            itemData.purchasedCount++;
            RefreshItemList();
        }

        public static string GetCategoryName(ShopCategory category)
        {
            return category switch
            {
                ShopCategory.Resource => "资源",
                ShopCategory.Hero => "英雄",
                ShopCategory.Tower => "防御塔",
                ShopCategory.Special => "特惠",
                _ => "未知"
            };
        }

        public static string GetCurrencySymbol(CurrencyType type)
        {
            return type switch
            {
                CurrencyType.Gold => "🪙",
                CurrencyType.Diamond => "💎",
                CurrencyType.Free => "🎁",
                _ => ""
            };
        }
    }
}

using UnityEngine;

namespace TowerDefense.Core
{
    public abstract class Singleton<T> : MonoBehaviour where T : MonoBehaviour
    {
        private static T _instance;
        private static readonly object _lock = new object();
        private static bool _applicationIsQuitting = false;

        public static T Instance
        {
            get
            {
                if (_applicationIsQuitting)
                {
                    Debug.LogWarning($"[Singleton] Instance '{typeof(T)}' already destroyed. Returning null.");
                    return null;
                }

                lock (_lock)
                {
                    if (_instance == null)
                    {
                        _instance = FindObjectOfType<T>();

                        if (_instance == null)
                        {
                            GameObject singleton = new GameObject($"(Singleton) {typeof(T)}");
                            _instance = singleton.AddComponent<T>();
                            DontDestroyOnLoad(singleton);
                        }
                    }
                    return _instance;
                }
            }
        }

        protected virtual void Awake()
        {
            if (_instance == null)
            {
                _instance = this as T;
                transform.SetParent(null);
                DontDestroyOnLoad(gameObject);
            }
            else if (_instance != this)
            {
                Destroy(gameObject);
            }
        }

        protected virtual void OnDestroy()
        {
            if (_instance == this)
            {
                _applicationIsQuitting = true;
            }
        }
    }
}

using System;
using System.Collections.Generic;
using UnityEngine;

namespace TowerDefense.Core
{
    public static class EventBus
    {
        private static readonly Dictionary<Type, Delegate> _events = new Dictionary<Type, Delegate>();

        public static void Subscribe<T>(Action<T> callback) where T : struct
        {
            Type eventType = typeof(T);
            if (_events.ContainsKey(eventType))
            {
                _events[eventType] = Delegate.Combine(_events[eventType], callback);
            }
            else
            {
                _events[eventType] = callback;
            }
        }

        public static void Unsubscribe<T>(Action<T> callback) where T : struct
        {
            Type eventType = typeof(T);
            if (_events.ContainsKey(eventType))
            {
                _events[eventType] = Delegate.Remove(_events[eventType], callback);
            }
        }

        public static void Publish<T>(T eventData) where T : struct
        {
            Type eventType = typeof(T);
            if (_events.ContainsKey(eventType))
            {
                (_events[eventType] as Action<T>)?.Invoke(eventData);
            }
        }

        public static void Clear()
        {
            _events.Clear();
        }
    }

    #region Event Data Structures

    public struct GameStartEvent { }
    public struct GamePauseEvent { public bool IsPaused; }
    public struct GameOverEvent { public bool IsVictory; }
    public struct WaveStartEvent { public int WaveIndex; }
    public struct WaveEndEvent { public int WaveIndex; }
    public struct EnemySpawnEvent { public GameObject Enemy; }
    public struct EnemyDeathEvent { public GameObject Enemy; public int Reward; }
    public struct EnemyReachEndEvent { public GameObject Enemy; public int Damage; }
    public struct TowerPlacedEvent { public GameObject Tower; public int Cost; }
    public struct TowerUpgradedEvent { public GameObject Tower; public int Level; }
    public struct TowerSoldEvent { public GameObject Tower; public int Refund; }
    public struct GoldChangedEvent { public int CurrentGold; public int Change; }
    public struct LifeChangedEvent { public int CurrentLife; public int Change; }
    public struct SkillUsedEvent { public string SkillName; }

    #endregion
}

