args.script:
var canvas = UnityEngine.GameObject.Find("Canvas");
if (canvas == null) { UnityEngine.Debug.Log("ERROR: Canvas not found"); return; }

// Add MainMenuUI to Canvas
var mmui = canvas.GetComponent<TowerDefense.UI.MainMenuUI>();
if (mmui == null)
{
    mmui = canvas.AddComponent<TowerDefense.UI.MainMenuUI>();
    UnityEngine.Debug.Log("Added MainMenuUI to Canvas");
}
else
{
    UnityEngine.Debug.Log("MainMenuUI already exists");
}

// Wire currency text fields via SerializedObject
var panel = UnityEngine.GameObject.Find("Canvas/Panel");
var goldText = panel.transform.Find("中间/金币")?.GetComponentInChildren<UnityEngine.UI.Text>();
var diamondText = panel.transform.Find("中间/钻石")?.GetComponentInChildren<UnityEngine.UI.Text>();
var staminaText = panel.transform.Find("中间/体力")?.GetComponentInChildren<UnityEngine.UI.Text>();

var so = new UnityEditor.SerializedObject(mmui);

string W(string field, UnityEngine.Object obj)
{
    var p = so.FindProperty(field);
    if (p == null) return "NOT_FOUND";
    p.objectReferenceValue = obj;
    return obj != null ? "OK" : "NULL";
}

UnityEngine.Debug.Log($"_goldText → {W("_goldText", goldText)}");
UnityEngine.Debug.Log($"_diamondText → {W("_diamondText", diamondText)}");
UnityEngine.Debug.Log($"_staminaText → {W("_staminaText", staminaText)}");

so.ApplyModifiedProperties();
UnityEngine.Debug.Log("MainMenuUI wired!");

// Also ensure PlayerWallet exists (it auto-creates as singleton but let's make one in scene)
var existing = UnityEngine.Object.FindObjectOfType<TowerDefense.Data.PlayerWallet>();
if (existing == null)
{
    var walletGO = new UnityEngine.GameObject("PlayerWallet");
    walletGO.AddComponent<TowerDefense.Data.PlayerWallet>();
    UnityEngine.Debug.Log("Created PlayerWallet in scene");
}
else
{
    UnityEngine.Debug.Log($"PlayerWallet already exists: {existing.gameObject.name}");
}

